import json, re
from pathlib import Path
p = Path('rllm_train/output/runs/run_1779771218/trajectories/step_0002.jsonl')
records = []
if p.exists():
    for line in p.read_text(errors='replace').splitlines():
        if line.strip():
            records.append(json.loads(line))
if not records:
    print('NO_RECORDS')
    raise SystemExit

def contents(record):
    for msg in record.get('chat_completions', []):
        c = msg.get('content', '')
        if isinstance(c, str):
            yield c
    rt = record.get('response_text', '')
    if isinstance(rt, str):
        yield rt

def has_finish(record):
    return any('finish' in c.lower() or '"name": "finish"' in c for c in contents(record))

def has_calculate(record):
    return any('calculate' in c.lower() or '"name": "calculate"' in c for c in contents(record))

def has_numeric(record):
    return any(re.search(r'-?\d+\.?\d*', c) for c in contents(record))

def finish_numeric(record):
    return has_finish(record) and has_numeric(record)
rewards = [float(r.get('reward', 0) or 0) for r in records]
mean = sum(rewards) / len(rewards)
rstd = (sum((x - mean) ** 2 for x in rewards) / len(rewards)) ** 0.5
print(json.dumps({
    'file': str(p),
    'count': len(records),
    'avg_reward': mean,
    'reward_std': rstd,
    'finish_rate': sum(has_finish(r) for r in records) / len(records),
    'finish_format_rate': sum(finish_numeric(r) for r in records) / len(records),
    'tool_usage_rate': sum(has_calculate(r) for r in records) / len(records),
    'answer_coverage': sum(has_numeric(r) for r in records) / len(records),
    'avg_agent_steps': sum(int(r.get('num_steps', 0) or 0) for r in records) / len(records),
}, ensure_ascii=False, indent=2))
