import time, re, json, subprocess, math
from pathlib import Path

time.sleep(120)
run = 'run_1779771218'
base = Path(f'rllm_train/output/runs/{run}')
log = base / 'training_log.txt'
text = log.read_text(errors='replace') if log.exists() else ''
print('---TAIL---')
print('\n'.join(text.splitlines()[-30:]) if text else 'LOG_EMPTY')

trl = []
for m in re.finditer(r'\[TRL_STEP\]\s+reward=([\d.eE+-]+)\s+loss=([\d.eE+-]+|nan|inf|-inf)\s+entropy=([\d.eE+-]+|nan|inf|-inf)\s+grad_norm=([\d.eE+-]+|nan|inf|-inf)\s+clipped_ratio=([\d.eE+-]+|nan|inf|-inf).*?step_time=([\d.eE+-]+)s', text):
    trl.append({
        'reward': float(m.group(1)),
        'loss': float(m.group(2)),
        'entropy': float(m.group(3)),
        'grad_norm': float(m.group(4)),
        'clip': float(m.group(5)),
        'time': float(m.group(6)),
    })
step = len(trl)

traj_metrics = {}
traj_dir = base / 'trajectories'
files = sorted(traj_dir.glob('step_*.jsonl')) if traj_dir.exists() else []
if files:
    p = files[-1]
    records = [json.loads(line) for line in p.read_text(errors='replace').splitlines() if line.strip()]
    if records:
        def contents(record):
            for msg in record.get('chat_completions', []):
                c = msg.get('content', '')
                if isinstance(c, str):
                    yield c
            rt = record.get('response_text', '')
            if isinstance(rt, str):
                yield rt
        def has_finish(record):
            return any('finish' in c.lower() or '"name": "finish"' in c for c in contents(record))
        def has_calculate(record):
            return any('calculate' in c.lower() or '"name": "calculate"' in c for c in contents(record))
        def has_numeric(record):
            return any(re.search(r'-?\d+\.?\d*', c) for c in contents(record))
        rewards = [float(r.get('reward', 0) or 0) for r in records]
        mean = sum(rewards) / len(rewards)
        traj_metrics = {
            'file': str(p),
            'rstd': (sum((x - mean) ** 2 for x in rewards) / len(rewards)) ** 0.5,
            'finish': sum(has_finish(r) for r in records) / len(records),
            'fmt': sum((has_finish(r) and has_numeric(r)) for r in records) / len(records),
            'tool': sum(has_calculate(r) for r in records) / len(records),
            'ans': sum(has_numeric(r) for r in records) / len(records),
            'avg_agent_steps': sum(int(r.get('num_steps', 0) or 0) for r in records) / len(records),
        }

proc = subprocess.run(['pgrep','-af',f'rllm_train.run_training.*{run}'], text=True, capture_output=True)
completed = 'Training Report' in text or not proc.stdout.strip()
print('---PARSED---')
print(json.dumps({'step': step, 'latest_trl': trl[-1] if trl else {}, 'trajectory': traj_metrics, 'completed': completed, 'process': bool(proc.stdout.strip())}, ensure_ascii=False, indent=2))
