    m=re.match(r'^\s*(\d+)/(\d+)\s+(\d+)\s+([-+\d.]+)\s+(?:([-+\d.]+|—|-|nan)\s+)?(?:([-+\d.]+|—|-|nan)\s+)?(?:([-+\d.]+|—|-|nan)\s+)?(?:([-+\d.]+|—|-|nan)\s+)?([\d.]+)s\s+([\d.]+)', l)
    if m:
        # ambiguous columns, but first columns stable step,total,trajs,reward; last rollout,tok/s
        summary.append({'step':int(m.group(1)), 'total':int(m.group(2)), 'trajs':int(m.group(3)), 'reward':float(m.group(4)), 'line':l.strip()})
