print('traj_files', len(files), files[:3], files[-3:] if files else [])

def text_of(obj):
    if obj is None: return ''
    if isinstance(obj,str): return obj
    try: return json.dumps(obj,ensure_ascii=False)
    except Exception: return str(obj)

def iter_msgs(record):
    for k in ('chat_completions','messages','conversation','trajectory'):
        v=record.get(k)
        if isinstance(v,list):
            for msg in v: yield msg

def all_text(record):
    parts=[record.get('response_text',''), record.get('completion',''), record.get('text','')]
    for msg in iter_msgs(record):
        if isinstance(msg,dict):
            parts.append(text_of(msg.get('content','')))
            parts.append(text_of(msg.get('tool_calls','')))
            parts.append(text_of(msg.get('function_call','')))
        else:
            parts.append(text_of(msg))
    return '\n'.join(text_of(p) for p in parts)

def tool_names(record):
    names=[]
    # explicit actions/tools fields
    for key in ('actions','tool_calls','tools'):
        v=record.get(key)
        if isinstance(v,list):
            for x in v:
                if isinstance(x,dict):
                    names.append(str(x.get('name') or x.get('tool') or x.get('function',{}).get('name','')))
    for msg in iter_msgs(record):
        if isinstance(msg,dict):
            tc=msg.get('tool_calls') or []
            if isinstance(tc,list):
                for x in tc:
                    if isinstance(x,dict):
                        fn=x.get('function') or {}
                        names.append(str(fn.get('name') or x.get('name') or ''))
    txt=all_text(record).lower()
    if re.search(r'\bfinish\s*\(', txt) or '"name": "finish"' in txt or "'name': 'finish'" in txt or 'finish' in names:
        names.append('finish')
    if re.search(r'\bcalculate\s*\(', txt) or '"name": "calculate"' in txt or "'name': 'calculate'" in txt or 'calculate' in names:
        names.append('calculate')
    return names

def has_finish(record): return 'finish' in [n.lower() for n in tool_names(record)]
